-- Built-in retail demo data, datasets, and showcase screen.
-- The demo datasource connection is synchronized at application startup from the active MySQL JDBC settings.

SET @crest_demo_schema_exists := (
  SELECT COUNT(*)
  FROM INFORMATION_SCHEMA.SCHEMATA
  WHERE SCHEMA_NAME = 'crest_demo_retail'
);
SET @crest_demo_rebuild_sql := IF(
  @crest_demo_schema_exists > 0,
  'DROP DATABASE `crest_demo_retail`',
  'DO 0'
);
PREPARE crest_demo_rebuild_stmt FROM @crest_demo_rebuild_sql;
EXECUTE crest_demo_rebuild_stmt;
DEALLOCATE PREPARE crest_demo_rebuild_stmt;

CREATE DATABASE `crest_demo_retail`
  DEFAULT CHARACTER SET utf8mb4
  DEFAULT COLLATE utf8mb4_0900_ai_ci;

CREATE TABLE `crest_demo_retail`.`dim_region` (
  `region_id` int NOT NULL,
  `region_name` varchar(32) NOT NULL,
  `province` varchar(32) NOT NULL,
  `city` varchar(32) NOT NULL,
  `city_tier` varchar(16) NOT NULL,
  PRIMARY KEY (`region_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE `crest_demo_retail`.`dim_store` (
  `store_id` int NOT NULL,
  `store_code` varchar(32) NOT NULL,
  `store_name` varchar(64) NOT NULL,
  `region_id` int NOT NULL,
  `channel` varchar(24) NOT NULL,
  `open_date` date NOT NULL,
  `area_level` varchar(16) NOT NULL,
  `manager_name` varchar(32) NOT NULL,
  `status` varchar(16) NOT NULL,
  PRIMARY KEY (`store_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE `crest_demo_retail`.`dim_product` (
  `product_id` int NOT NULL,
  `sku_code` varchar(32) NOT NULL,
  `product_name` varchar(64) NOT NULL,
  `category` varchar(32) NOT NULL,
  `series_name` varchar(32) NOT NULL,
  `list_price` decimal(10,2) NOT NULL,
  `cost_price` decimal(10,2) NOT NULL,
  `launch_date` date NOT NULL,
  `is_signature` tinyint NOT NULL,
  PRIMARY KEY (`product_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE `crest_demo_retail`.`dim_member` (
  `member_id` int NOT NULL,
  `member_no` varchar(32) NOT NULL,
  `gender` varchar(8) NOT NULL,
  `age_group` varchar(16) NOT NULL,
  `city` varchar(32) NOT NULL,
  `register_channel` varchar(24) NOT NULL,
  `member_level` varchar(16) NOT NULL,
  `register_date` date NOT NULL,
  PRIMARY KEY (`member_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE `crest_demo_retail`.`fact_orders` (
  `order_id` bigint NOT NULL,
  `order_no` varchar(40) NOT NULL,
  `order_date` date NOT NULL,
  `order_hour` int NOT NULL,
  `store_id` int NOT NULL,
  `member_id` int NOT NULL,
  `order_channel` varchar(24) NOT NULL,
  `pay_method` varchar(24) NOT NULL,
  `gross_amount` decimal(12,2) NOT NULL,
  `discount_amount` decimal(12,2) NOT NULL,
  `net_amount` decimal(12,2) NOT NULL,
  `delivery_fee` decimal(10,2) NOT NULL,
  `order_status` varchar(16) NOT NULL,
  PRIMARY KEY (`order_id`),
  KEY `idx_order_date` (`order_date`),
  KEY `idx_store` (`store_id`),
  KEY `idx_member` (`member_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE `crest_demo_retail`.`fact_order_items` (
  `item_id` bigint NOT NULL,
  `order_id` bigint NOT NULL,
  `product_id` int NOT NULL,
  `quantity` int NOT NULL,
  `unit_price` decimal(10,2) NOT NULL,
  `item_discount` decimal(10,2) NOT NULL,
  `item_amount` decimal(12,2) NOT NULL,
  PRIMARY KEY (`item_id`),
  KEY `idx_order` (`order_id`),
  KEY `idx_product` (`product_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE `crest_demo_retail`.`fact_delivery_daily` (
  `delivery_id` bigint NOT NULL,
  `stat_date` date NOT NULL,
  `store_id` int NOT NULL,
  `platform` varchar(24) NOT NULL,
  `delivery_orders` int NOT NULL,
  `avg_delivery_minutes` decimal(8,2) NOT NULL,
  `timeout_orders` int NOT NULL,
  `bad_review_orders` int NOT NULL,
  PRIMARY KEY (`delivery_id`),
  KEY `idx_delivery_date` (`stat_date`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE `crest_demo_retail`.`fact_inventory_daily` (
  `inventory_id` bigint NOT NULL,
  `stat_date` date NOT NULL,
  `store_id` int NOT NULL,
  `product_id` int NOT NULL,
  `opening_qty` int NOT NULL,
  `inbound_qty` int NOT NULL,
  `sold_qty` int NOT NULL,
  `waste_qty` int NOT NULL,
  `closing_qty` int NOT NULL,
  `stockout_flag` tinyint NOT NULL,
  PRIMARY KEY (`inventory_id`),
  KEY `idx_inv_date` (`stat_date`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE `crest_demo_retail`.`fact_marketing_campaign` (
  `campaign_id` int NOT NULL,
  `campaign_name` varchar(64) NOT NULL,
  `campaign_type` varchar(24) NOT NULL,
  `start_date` date NOT NULL,
  `end_date` date NOT NULL,
  `target_channel` varchar(24) NOT NULL,
  `budget_amount` decimal(12,2) NOT NULL,
  `coupon_cost` decimal(12,2) NOT NULL,
  `exposure_uv` int NOT NULL,
  `conversion_orders` int NOT NULL,
  `attributed_revenue` decimal(12,2) NOT NULL,
  PRIMARY KEY (`campaign_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE `crest_demo_retail`.`fact_member_behavior_daily` (
  `behavior_id` bigint NOT NULL,
  `stat_date` date NOT NULL,
  `member_id` int NOT NULL,
  `visits` int NOT NULL,
  `add_cart_count` int NOT NULL,
  `coupon_received` int NOT NULL,
  `coupon_used` int NOT NULL,
  `app_active_seconds` int NOT NULL,
  PRIMARY KEY (`behavior_id`),
  KEY `idx_behavior_date` (`stat_date`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

TRUNCATE TABLE `crest_demo_retail`.`fact_order_items`;
TRUNCATE TABLE `crest_demo_retail`.`fact_orders`;
TRUNCATE TABLE `crest_demo_retail`.`fact_delivery_daily`;
TRUNCATE TABLE `crest_demo_retail`.`fact_inventory_daily`;
TRUNCATE TABLE `crest_demo_retail`.`fact_marketing_campaign`;
TRUNCATE TABLE `crest_demo_retail`.`fact_member_behavior_daily`;
TRUNCATE TABLE `crest_demo_retail`.`dim_region`;
TRUNCATE TABLE `crest_demo_retail`.`dim_store`;
TRUNCATE TABLE `crest_demo_retail`.`dim_product`;
TRUNCATE TABLE `crest_demo_retail`.`dim_member`;

CREATE TABLE `crest_demo_retail`.`_crest_digits` (`d` int NOT NULL PRIMARY KEY);
