INSERT INTO `crest_demo_retail`.`dim_product`
SELECT n, CONCAT('SKU-', LPAD(n, 4, '0')), CONCAT(ELT((n % 12) + 1, '青提茉莉', '厚乳拿铁', '桂花乌龙', '手捣柠檬茶', '杨枝甘露', '生椰冷萃', '芋泥波波', '黑糖珍珠', '莓莓酸奶', '芝士桃桃', '海盐焦糖', '轻乳茶'), ' ', ELT((n % 4) + 1, '标准杯', '加料版', '低糖版', '季节款')), ELT((n % 6) + 1, '茶饮', '咖啡', '烘焙', '轻食', '周边', '季节限定'), ELT((n % 8) + 1, '经典系列', '厚乳系列', '水果系列', '轻负担系列', '早餐系列', '下午茶系列', '城市限定', '会员专享'), ROUND(18 + (n % 28) * 1.4 + IF(n % 11 = 0, 8, 0), 2), ROUND((18 + (n % 28) * 1.4 + IF(n % 11 = 0, 8, 0)) * (0.32 + (n % 5) * 0.035), 2), DATE_SUB(CURRENT_DATE(), INTERVAL (n * 7 % 900) DAY), IF(n % 5 IN (0, 1), 1, 0)
FROM (SELECT d0.d + d1.d * 10 + d2.d * 100 + 1 AS n FROM `crest_demo_retail`.`_crest_digits` d0 CROSS JOIN `crest_demo_retail`.`_crest_digits` d1 CROSS JOIN `crest_demo_retail`.`_crest_digits` d2) seq WHERE n <= 96;

INSERT INTO `crest_demo_retail`.`dim_member`
SELECT n, CONCAT('MB', LPAD(n, 6, '0')), IF(n % 3 = 0, '男', '女'), ELT((n % 5) + 1, '18-24', '25-30', '31-35', '36-45', '46+'), ELT((n % 8) + 1, '上海', '北京', '广州', '成都', '武汉', '杭州', '深圳', '西安'), ELT((n % 5) + 1, '小程序', '门店扫码', '外卖平台', '社群活动', '企业团购'), CASE WHEN n % 100 < 6 THEN '黑金' WHEN n % 100 < 20 THEN '钻石' WHEN n % 100 < 46 THEN '黄金' WHEN n % 100 < 76 THEN '白银' ELSE '普通' END, DATE_SUB(CURRENT_DATE(), INTERVAL (n * 11 % 1080) DAY)
FROM (SELECT d0.d + d1.d * 10 + d2.d * 100 + d3.d * 1000 + 1 AS n FROM `crest_demo_retail`.`_crest_digits` d0 CROSS JOIN `crest_demo_retail`.`_crest_digits` d1 CROSS JOIN `crest_demo_retail`.`_crest_digits` d2 CROSS JOIN `crest_demo_retail`.`_crest_digits` d3) seq WHERE n <= 6000;

INSERT INTO `crest_demo_retail`.`fact_orders`
SELECT 202600000000 + n, CONCAT('OD', DATE_FORMAT(order_date, '%Y%m%d'), LPAD(n, 6, '0')), order_date, order_hour, store_id, member_id, order_channel, pay_method, gross_amount, ROUND(gross_amount * discount_rate, 2), ROUND(gross_amount - gross_amount * discount_rate + IF(order_channel = '外卖', 3.50, 0), 2), IF(order_channel = '外卖', 3.50, 0), IF(n % 97 = 0, '已取消', '已完成')
FROM (SELECT n, DATE_SUB(CURRENT_DATE(), INTERVAL (n % 180) DAY) AS order_date, CASE WHEN n % 24 BETWEEN 6 AND 10 THEN 8 + (n % 4) WHEN n % 24 BETWEEN 11 AND 16 THEN 12 + (n % 5) ELSE 17 + (n % 6) END AS order_hour, ((n * 7) % 36) + 1 AS store_id, ((n * 13) % 6000) + 1 AS member_id, ELT((n % 5) + 1, '门店', '小程序', '外卖', '企业团购', '自助点单') AS order_channel, ELT((n % 4) + 1, '微信', '支付宝', '会员余额', '企业月结') AS pay_method, ROUND(34 + (n % 90) * 0.86 + IF(n % 7 IN (0, 6), 16, 0) + IF(n % 17 = 0, 38, 0), 2) AS gross_amount, CASE WHEN n % 5 = 1 THEN 0.08 WHEN n % 5 = 2 THEN 0.05 WHEN n % 5 = 3 THEN 0.12 ELSE 0.03 END AS discount_rate FROM (SELECT d0.d + d1.d * 10 + d2.d * 100 + d3.d * 1000 + d4.d * 10000 + 1 AS n FROM `crest_demo_retail`.`_crest_digits` d0 CROSS JOIN `crest_demo_retail`.`_crest_digits` d1 CROSS JOIN `crest_demo_retail`.`_crest_digits` d2 CROSS JOIN `crest_demo_retail`.`_crest_digits` d3 CROSS JOIN `crest_demo_retail`.`_crest_digits` d4) seq WHERE n <= 32000) orders_seed;

INSERT INTO `crest_demo_retail`.`fact_order_items`
SELECT o.order_id * 10 + slot.slot, o.order_id, p.product_id, qty.quantity, p.list_price, ROUND(p.list_price * qty.quantity * IF(o.order_channel = '企业团购', 0.10, IF(o.order_channel = '小程序', 0.06, 0.03)), 2), ROUND(p.list_price * qty.quantity * (1 - IF(o.order_channel = '企业团购', 0.10, IF(o.order_channel = '小程序', 0.06, 0.03))), 2)
FROM `crest_demo_retail`.`fact_orders` o JOIN (SELECT 1 AS slot UNION ALL SELECT 2 UNION ALL SELECT 3) slot ON slot.slot <= IF(o.order_id % 5 = 0, 3, 2) JOIN `crest_demo_retail`.`dim_product` p ON p.product_id = ((o.order_id + slot.slot * 17) % 96) + 1 CROSS JOIN LATERAL (SELECT IF((o.order_id + slot.slot) % 7 = 0, 2, 1) AS quantity) qty;

INSERT INTO `crest_demo_retail`.`fact_delivery_daily`
SELECT day_seq.n * 108 + s.store_id * 3 + platform.platform_id, DATE_SUB(CURRENT_DATE(), INTERVAL day_seq.n DAY), s.store_id, platform.platform_name, delivery_seed.delivery_orders, ROUND(22 + ((s.store_id + day_seq.n + platform.platform_id * 5) % 24) * 0.65, 2), FLOOR(delivery_seed.delivery_orders * (0.015 + ((s.store_id + day_seq.n + platform.platform_id) % 7) / 1000)), FLOOR(delivery_seed.delivery_orders * (0.006 + ((s.store_id + day_seq.n) % 5) / 1800))
FROM (SELECT d0.d + d1.d * 10 AS n FROM `crest_demo_retail`.`_crest_digits` d0 CROSS JOIN `crest_demo_retail`.`_crest_digits` d1) day_seq JOIN `crest_demo_retail`.`dim_store` s ON s.status = '营业' JOIN (SELECT 1 AS platform_id, '美团外卖' AS platform_name UNION ALL SELECT 2, '饿了么' UNION ALL SELECT 3, '自营配送') platform CROSS JOIN LATERAL (SELECT 22 + ((s.store_id * 3 + day_seq.n + platform.platform_id * 7) % 78) AS delivery_orders) delivery_seed WHERE day_seq.n < 90;

INSERT INTO `crest_demo_retail`.`fact_inventory_daily`
SELECT day_seq.n * 720 + s.store_id * 20 + p.product_id, DATE_SUB(CURRENT_DATE(), INTERVAL day_seq.n DAY), s.store_id, p.product_id, inv_seed.opening_qty, inv_seed.inbound_qty, inv_seed.sold_qty, inv_seed.waste_qty, GREATEST(0, inv_seed.opening_qty + inv_seed.inbound_qty - inv_seed.sold_qty - inv_seed.waste_qty), IF(GREATEST(0, inv_seed.opening_qty + inv_seed.inbound_qty - inv_seed.sold_qty - inv_seed.waste_qty) < 12 OR (day_seq.n + s.store_id + p.product_id) % 37 = 0, 1, 0)
FROM (SELECT d0.d + d1.d * 10 AS n FROM `crest_demo_retail`.`_crest_digits` d0 CROSS JOIN `crest_demo_retail`.`_crest_digits` d1) day_seq JOIN `crest_demo_retail`.`dim_store` s ON s.status = '营业' JOIN `crest_demo_retail`.`dim_product` p ON p.product_id <= 20 CROSS JOIN LATERAL (SELECT 38 + ((day_seq.n + s.store_id + p.product_id) % 92) AS opening_qty, 8 + ((day_seq.n * 2 + p.product_id) % 34) AS inbound_qty, 18 + ((s.store_id * 3 + p.product_id * 2 + day_seq.n) % 58) AS sold_qty, IF((day_seq.n + p.product_id) % 9 = 0, 3 + (s.store_id % 5), 1 + (p.product_id % 3)) AS waste_qty) inv_seed WHERE day_seq.n < 25;

INSERT INTO `crest_demo_retail`.`fact_marketing_campaign` VALUES
(1,'春季新品上新','新品首发',DATE_SUB(CURRENT_DATE(), INTERVAL 170 DAY),DATE_SUB(CURRENT_DATE(), INTERVAL 142 DAY),'小程序',68000,18400,512000,5180,358600),(2,'午间第二杯半价','拉新促活',DATE_SUB(CURRENT_DATE(), INTERVAL 154 DAY),DATE_SUB(CURRENT_DATE(), INTERVAL 126 DAY),'门店',52000,22800,388000,4360,279400),(3,'会员日加倍积分','会员运营',DATE_SUB(CURRENT_DATE(), INTERVAL 139 DAY),DATE_SUB(CURRENT_DATE(), INTERVAL 125 DAY),'会员体系',39000,14600,226000,3180,226900),(4,'外卖免配送券','渠道增长',DATE_SUB(CURRENT_DATE(), INTERVAL 121 DAY),DATE_SUB(CURRENT_DATE(), INTERVAL 92 DAY),'外卖',74000,31500,486000,6020,401300),(5,'城市限定联名','品牌联名',DATE_SUB(CURRENT_DATE(), INTERVAL 102 DAY),DATE_SUB(CURRENT_DATE(), INTERVAL 75 DAY),'社媒',112000,26800,768000,6840,552700),(6,'早餐轻食组合','场景拓展',DATE_SUB(CURRENT_DATE(), INTERVAL 87 DAY),DATE_SUB(CURRENT_DATE(), INTERVAL 61 DAY),'门店',46000,12600,242000,2840,184500),(7,'企业下午茶团购','B端团购',DATE_SUB(CURRENT_DATE(), INTERVAL 72 DAY),DATE_SUB(CURRENT_DATE(), INTERVAL 45 DAY),'企业团购',58000,9800,116000,1460,318400),(8,'暑期校园季','校园运营',DATE_SUB(CURRENT_DATE(), INTERVAL 64 DAY),DATE_SUB(CURRENT_DATE(), INTERVAL 36 DAY),'校园',62000,17600,342000,3920,268900),(9,'周末家庭分享装','复购提升',DATE_SUB(CURRENT_DATE(), INTERVAL 50 DAY),DATE_SUB(CURRENT_DATE(), INTERVAL 22 DAY),'小程序',69000,22100,438000,4710,326800),(10,'直播间限时券','内容转化',DATE_SUB(CURRENT_DATE(), INTERVAL 37 DAY),DATE_SUB(CURRENT_DATE(), INTERVAL 18 DAY),'直播',84000,25800,694000,5360,419600),(11,'高温补水季','季节营销',DATE_SUB(CURRENT_DATE(), INTERVAL 24 DAY),DATE_SUB(CURRENT_DATE(), INTERVAL 5 DAY),'外卖',76000,30200,572000,6120,463900),(12,'黑金会员专享','高价值会员',DATE_SUB(CURRENT_DATE(), INTERVAL 18 DAY),CURRENT_DATE(),'会员体系',42000,11800,188000,1960,214600);

INSERT INTO `crest_demo_retail`.`fact_member_behavior_daily`
SELECT day_seq.n * 6000 + m.member_id, DATE_SUB(CURRENT_DATE(), INTERVAL day_seq.n DAY), m.member_id, 1 + ((m.member_id + day_seq.n) % 5), IF((m.member_id + day_seq.n) % 3 = 0, 1 + (m.member_id % 3), m.member_id % 2), IF((m.member_id + day_seq.n) % 4 = 0, 1, 0), IF((m.member_id + day_seq.n) % 9 = 0, 1, 0), 60 + ((m.member_id * 13 + day_seq.n * 17) % 1800)
FROM (SELECT d0.d AS n FROM `crest_demo_retail`.`_crest_digits` d0 WHERE d0.d < 5) day_seq JOIN `crest_demo_retail`.`dim_member` m;

DROP TABLE IF EXISTS `crest_demo_retail`.`_crest_digits`;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_daily_sales` AS select date_format(`o`.`order_date`,'%Y-%m-%d') AS `order_date`,`r`.`region_name` AS `region_name`,`r`.`city` AS `city`,`s`.`store_name` AS `store_name`,`o`.`order_channel` AS `order_channel`,count(distinct `o`.`order_id`) AS `order_count`,count(distinct `o`.`member_id`) AS `buyer_count`,round(sum(`o`.`net_amount`),2) AS `revenue`,round(sum(`o`.`discount_amount`),2) AS `discount_amount`,round(avg(`o`.`net_amount`),2) AS `avg_order_amount` from ((`crest_demo_retail`.`fact_orders` `o` join `crest_demo_retail`.`dim_store` `s` on((`o`.`store_id` = `s`.`store_id`))) join `crest_demo_retail`.`dim_region` `r` on((`s`.`region_id` = `r`.`region_id`))) where (`o`.`order_status` = '已完成') group by date_format(`o`.`order_date`,'%Y-%m-%d'),`r`.`region_name`,`r`.`city`,`s`.`store_name`,`o`.`order_channel`;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_dashboard_kpi` AS select round(`o`.`revenue`,2) AS `revenue_180d`,`o`.`orders` AS `orders_180d`,`o`.`buyers` AS `buyers_180d`,round((`o`.`revenue` / nullif(`o`.`orders`,0)),2) AS `avg_order_amount`,round(((`o`.`discount_amount` / nullif(`o`.`gross_amount`,0)) * 100),2) AS `discount_rate_pct`,round(`p`.`gross_profit`,2) AS `gross_profit_180d`,round(((`p`.`gross_profit` / nullif(`p`.`item_sales`,0)) * 100),2) AS `gross_margin_pct`,round((`d`.`on_time_rate` * 100),2) AS `delivery_on_time_pct`,round((`i`.`stockout_rate` * 100),2) AS `stockout_rate_pct`,round(`c`.`avg_roi`,2) AS `avg_campaign_roi`,`s`.`active_stores` AS `active_stores`,round(((`sig`.`signature_revenue` / nullif(`p`.`item_sales`,0)) * 100),2) AS `signature_revenue_pct` from (((((((select sum(`crest_demo_retail`.`fact_orders`.`net_amount`) AS `revenue`,sum(`crest_demo_retail`.`fact_orders`.`gross_amount`) AS `gross_amount`,sum(`crest_demo_retail`.`fact_orders`.`discount_amount`) AS `discount_amount`,count(distinct `crest_demo_retail`.`fact_orders`.`order_id`) AS `orders`,count(distinct `crest_demo_retail`.`fact_orders`.`member_id`) AS `buyers` from `crest_demo_retail`.`fact_orders` where (`crest_demo_retail`.`fact_orders`.`order_status` = '已完成')) `o` join (select sum(`oi`.`item_amount`) AS `item_sales`,sum((`oi`.`item_amount` - (`oi`.`quantity` * `p`.`cost_price`))) AS `gross_profit` from ((`crest_demo_retail`.`fact_order_items` `oi` join `crest_demo_retail`.`fact_orders` `fo` on(((`fo`.`order_id` = `oi`.`order_id`) and (`fo`.`order_status` = '已完成')))) join `crest_demo_retail`.`dim_product` `p` on((`p`.`product_id` = `oi`.`product_id`)))) `p`) join (select (1 - (sum(`crest_demo_retail`.`fact_delivery_daily`.`timeout_orders`) / nullif(sum(`crest_demo_retail`.`fact_delivery_daily`.`delivery_orders`),0))) AS `on_time_rate` from `crest_demo_retail`.`fact_delivery_daily`) `d`) join (select (sum(`crest_demo_retail`.`fact_inventory_daily`.`stockout_flag`) / nullif(count(0),0)) AS `stockout_rate` from `crest_demo_retail`.`fact_inventory_daily`) `i`) join (select avg((`crest_demo_retail`.`fact_marketing_campaign`.`attributed_revenue` / nullif((`crest_demo_retail`.`fact_marketing_campaign`.`budget_amount` + `crest_demo_retail`.`fact_marketing_campaign`.`coupon_cost`),0))) AS `avg_roi` from `crest_demo_retail`.`fact_marketing_campaign`) `c`) join (select count(0) AS `active_stores` from `crest_demo_retail`.`dim_store` where (`crest_demo_retail`.`dim_store`.`status` = '营业')) `s`) join (select sum(`oi`.`item_amount`) AS `signature_revenue` from ((`crest_demo_retail`.`fact_order_items` `oi` join `crest_demo_retail`.`fact_orders` `fo` on(((`fo`.`order_id` = `oi`.`order_id`) and (`fo`.`order_status` = '已完成')))) join `crest_demo_retail`.`dim_product` `p` on((`p`.`product_id` = `oi`.`product_id`))) where (`p`.`is_signature` = 1)) `sig`);

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_channel_daily` AS select date_format(`o`.`order_date`,'%m-%d') AS `order_date`,`o`.`order_channel` AS `order_channel`,count(distinct `o`.`order_id`) AS `order_count`,count(distinct `o`.`member_id`) AS `buyer_count`,round(sum(`o`.`net_amount`),2) AS `revenue`,round((sum(`o`.`net_amount`) / nullif(count(distinct `o`.`order_id`),0)),2) AS `avg_order_amount` from `crest_demo_retail`.`fact_orders` `o` where ((`o`.`order_status` = '已完成') and (`o`.`order_date` >= (select (max(`crest_demo_retail`.`fact_orders`.`order_date`) - interval 89 day) from `crest_demo_retail`.`fact_orders` where (`crest_demo_retail`.`fact_orders`.`order_status` = '已完成')))) group by date_format(`o`.`order_date`,'%m-%d'),`o`.`order_channel` order by min(`o`.`order_date`),`o`.`order_channel`;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_store_performance` AS select `s`.`store_id` AS `store_id`,`s`.`store_name` AS `store_name`,`r`.`region_name` AS `region_name`,`r`.`city` AS `city`,`s`.`channel` AS `channel`,coalesce(`o`.`order_count`,0) AS `order_count`,coalesce(`o`.`revenue`,0) AS `revenue`,coalesce(`p`.`gross_profit`,0) AS `gross_profit`,round((coalesce(`p`.`gross_profit`,0) / nullif(`p`.`item_sales`,0)),4) AS `gross_margin`,round(coalesce(`d`.`avg_delivery_minutes`,0),2) AS `avg_delivery_minutes`,coalesce(`d`.`timeout_orders`,0) AS `timeout_orders` from ((((`crest_demo_retail`.`dim_store` `s` join `crest_demo_retail`.`dim_region` `r` on((`s`.`region_id` = `r`.`region_id`))) left join (select `crest_demo_retail`.`fact_orders`.`store_id` AS `store_id`,count(distinct `crest_demo_retail`.`fact_orders`.`order_id`) AS `order_count`,round(sum(`crest_demo_retail`.`fact_orders`.`net_amount`),2) AS `revenue` from `crest_demo_retail`.`fact_orders` where (`crest_demo_retail`.`fact_orders`.`order_status` = '已完成') group by `crest_demo_retail`.`fact_orders`.`store_id`) `o` on((`s`.`store_id` = `o`.`store_id`))) left join (select `fo`.`store_id` AS `store_id`,round(sum(`oi`.`item_amount`),2) AS `item_sales`,round(sum((`oi`.`item_amount` - (`oi`.`quantity` * `p`.`cost_price`))),2) AS `gross_profit` from ((`crest_demo_retail`.`fact_order_items` `oi` join `crest_demo_retail`.`fact_orders` `fo` on(((`fo`.`order_id` = `oi`.`order_id`) and (`fo`.`order_status` = '已完成')))) join `crest_demo_retail`.`dim_product` `p` on((`p`.`product_id` = `oi`.`product_id`))) group by `fo`.`store_id`) `p` on((`s`.`store_id` = `p`.`store_id`))) left join (select `crest_demo_retail`.`fact_delivery_daily`.`store_id` AS `store_id`,avg(`crest_demo_retail`.`fact_delivery_daily`.`avg_delivery_minutes`) AS `avg_delivery_minutes`,sum(`crest_demo_retail`.`fact_delivery_daily`.`timeout_orders`) AS `timeout_orders` from `crest_demo_retail`.`fact_delivery_daily` group by `crest_demo_retail`.`fact_delivery_daily`.`store_id`) `d` on((`s`.`store_id` = `d`.`store_id`))) order by `revenue` desc limit 16;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_product_rank` AS select `p`.`product_id` AS `product_id`,`p`.`product_name` AS `product_name`,`p`.`category` AS `category`,`p`.`series_name` AS `series_name`,sum(`oi`.`quantity`) AS `sold_quantity`,round(sum(`oi`.`item_amount`),2) AS `sales_amount`,round(sum((`oi`.`item_amount` - (`oi`.`quantity` * `p`.`cost_price`))),2) AS `gross_profit`,count(distinct `oi`.`order_id`) AS `order_count` from ((`crest_demo_retail`.`dim_product` `p` join `crest_demo_retail`.`fact_order_items` `oi` on((`p`.`product_id` = `oi`.`product_id`))) join `crest_demo_retail`.`fact_orders` `o` on(((`oi`.`order_id` = `o`.`order_id`) and (`o`.`order_status` = '已完成')))) group by `p`.`product_id`,`p`.`product_name`,`p`.`category`,`p`.`series_name` order by `gross_profit` desc limit 18;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_inventory_risk` AS select `s`.`store_name` AS `store_name`,`r`.`region_name` AS `region_name`,`p`.`category` AS `category`,sum(`i`.`stockout_flag`) AS `stockout_days`,sum(`i`.`waste_qty`) AS `waste_qty`,sum(`i`.`sold_qty`) AS `sold_qty`,round(((sum(`i`.`sold_qty`) / nullif(sum((`i`.`opening_qty` + `i`.`inbound_qty`)),0)) * 100),2) AS `sell_through_rate`,round((((sum(`i`.`stockout_flag`) * 8) + ((sum(`i`.`waste_qty`) / nullif((sum(`i`.`sold_qty`) + 1),0)) * 120)) + ((100 - ((sum(`i`.`sold_qty`) / nullif(sum((`i`.`opening_qty` + `i`.`inbound_qty`)),0)) * 100)) * 0.45)),2) AS `risk_score` from (((`crest_demo_retail`.`fact_inventory_daily` `i` join `crest_demo_retail`.`dim_store` `s` on((`s`.`store_id` = `i`.`store_id`))) join `crest_demo_retail`.`dim_region` `r` on((`r`.`region_id` = `s`.`region_id`))) join `crest_demo_retail`.`dim_product` `p` on((`p`.`product_id` = `i`.`product_id`))) group by `s`.`store_name`,`r`.`region_name`,`p`.`category` order by `risk_score` desc limit 18;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_member_value` AS select `m`.`member_level` AS `member_level`,'全部' AS `age_group`,'全部' AS `city`,count(distinct `m`.`member_id`) AS `member_count`,count(distinct `o`.`order_id`) AS `order_count`,round(coalesce(sum(`o`.`net_amount`),0),2) AS `revenue`,round((coalesce(sum(`o`.`net_amount`),0) / nullif(count(distinct `m`.`member_id`),0)),2) AS `arpu` from (`crest_demo_retail`.`dim_member` `m` left join `crest_demo_retail`.`fact_orders` `o` on(((`m`.`member_id` = `o`.`member_id`) and (`o`.`order_status` = '已完成')))) group by `m`.`member_level`;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_campaign_roi` AS select `crest_demo_retail`.`fact_marketing_campaign`.`campaign_id` AS `campaign_id`,`crest_demo_retail`.`fact_marketing_campaign`.`campaign_name` AS `campaign_name`,`crest_demo_retail`.`fact_marketing_campaign`.`campaign_type` AS `campaign_type`,`crest_demo_retail`.`fact_marketing_campaign`.`target_channel` AS `target_channel`,`crest_demo_retail`.`fact_marketing_campaign`.`budget_amount` AS `budget_amount`,`crest_demo_retail`.`fact_marketing_campaign`.`coupon_cost` AS `coupon_cost`,`crest_demo_retail`.`fact_marketing_campaign`.`exposure_uv` AS `exposure_uv`,`crest_demo_retail`.`fact_marketing_campaign`.`conversion_orders` AS `conversion_orders`,`crest_demo_retail`.`fact_marketing_campaign`.`attributed_revenue` AS `attributed_revenue`,round((`crest_demo_retail`.`fact_marketing_campaign`.`conversion_orders` / nullif(`crest_demo_retail`.`fact_marketing_campaign`.`exposure_uv`,0)),4) AS `conversion_rate`,round((`crest_demo_retail`.`fact_marketing_campaign`.`attributed_revenue` / nullif((`crest_demo_retail`.`fact_marketing_campaign`.`budget_amount` + `crest_demo_retail`.`fact_marketing_campaign`.`coupon_cost`),0)),2) AS `roi` from `crest_demo_retail`.`fact_marketing_campaign`;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_growth_funnel` AS select '曝光触达' AS `stage_name`,sum(`crest_demo_retail`.`fact_marketing_campaign`.`exposure_uv`) AS `stage_value`,1 AS `stage_order` from `crest_demo_retail`.`fact_marketing_campaign` union all select '到店/访问' AS `到店/访问`,sum(`crest_demo_retail`.`fact_member_behavior_daily`.`visits`) AS `SUM(visits)`,2 AS `2` from `crest_demo_retail`.`fact_member_behavior_daily` union all select '加入购物车' AS `加入购物车`,sum(`crest_demo_retail`.`fact_member_behavior_daily`.`add_cart_count`) AS `SUM(add_cart_count)`,3 AS `3` from `crest_demo_retail`.`fact_member_behavior_daily` union all select '领券用户' AS `领券用户`,sum(`crest_demo_retail`.`fact_member_behavior_daily`.`coupon_received`) AS `SUM(coupon_received)`,4 AS `4` from `crest_demo_retail`.`fact_member_behavior_daily` union all select '用券转化' AS `用券转化`,sum(`crest_demo_retail`.`fact_member_behavior_daily`.`coupon_used`) AS `SUM(coupon_used)`,5 AS `5` from `crest_demo_retail`.`fact_member_behavior_daily` union all select '完成订单' AS `完成订单`,count(distinct `crest_demo_retail`.`fact_orders`.`order_id`) AS `COUNT(DISTINCT order_id)`,6 AS `6` from `crest_demo_retail`.`fact_orders` where (`crest_demo_retail`.`fact_orders`.`order_status` = '已完成') union all select '复购会员' AS `复购会员`,count(0) AS `COUNT(*)`,7 AS `7` from (select `crest_demo_retail`.`fact_orders`.`member_id` AS `member_id` from `crest_demo_retail`.`fact_orders` where (`crest_demo_retail`.`fact_orders`.`order_status` = '已完成') group by `crest_demo_retail`.`fact_orders`.`member_id` having (count(0) >= 2)) `t`;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_hour_channel_sales` AS select concat(lpad(`o`.`order_hour`,2,'0'),':00') AS `hour_label`,`o`.`order_channel` AS `order_channel`,count(distinct `o`.`order_id`) AS `order_count`,round(sum(`o`.`net_amount`),2) AS `revenue`,round((sum(`o`.`net_amount`) / nullif(count(distinct `o`.`order_id`),0)),2) AS `avg_order_amount` from `crest_demo_retail`.`fact_orders` `o` where (`o`.`order_status` = '已完成') group by `o`.`order_hour`,`o`.`order_channel` order by `o`.`order_hour`,`o`.`order_channel`;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_service_platform` AS select `crest_demo_retail`.`fact_delivery_daily`.`platform` AS `platform`,95.00 AS `target_on_time_rate`,round(((1 - (sum(`crest_demo_retail`.`fact_delivery_daily`.`timeout_orders`) / nullif(sum(`crest_demo_retail`.`fact_delivery_daily`.`delivery_orders`),0))) * 100),2) AS `on_time_rate`,round(avg(`crest_demo_retail`.`fact_delivery_daily`.`avg_delivery_minutes`),2) AS `avg_delivery_minutes`,sum(`crest_demo_retail`.`fact_delivery_daily`.`timeout_orders`) AS `timeout_orders`,round(((sum(`crest_demo_retail`.`fact_delivery_daily`.`bad_review_orders`) / nullif(sum(`crest_demo_retail`.`fact_delivery_daily`.`delivery_orders`),0)) * 100),2) AS `bad_review_rate`,sum(`crest_demo_retail`.`fact_delivery_daily`.`delivery_orders`) AS `delivery_orders`,round(((100 - ((sum(`crest_demo_retail`.`fact_delivery_daily`.`timeout_orders`) / nullif(sum(`crest_demo_retail`.`fact_delivery_daily`.`delivery_orders`),0)) * 55)) - ((sum(`crest_demo_retail`.`fact_delivery_daily`.`bad_review_orders`) / nullif(sum(`crest_demo_retail`.`fact_delivery_daily`.`delivery_orders`),0)) * 45)),2) AS `satisfaction_score` from `crest_demo_retail`.`fact_delivery_daily` group by `crest_demo_retail`.`fact_delivery_daily`.`platform` order by `delivery_orders` desc;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_region_profit_matrix` AS select `r`.`region_name` AS `region_name`,`r`.`city` AS `city`,count(distinct `s`.`store_id`) AS `active_stores`,coalesce(`o`.`order_count`,0) AS `order_count`,round(coalesce(`o`.`revenue`,0),2) AS `revenue`,round(coalesce(`p`.`gross_profit`,0),2) AS `gross_profit`,round(((coalesce(`p`.`gross_profit`,0) / nullif(`p`.`item_sales`,0)) * 100),2) AS `gross_margin_pct`,coalesce(`o`.`buyer_count`,0) AS `buyer_count`,round((coalesce(`o`.`revenue`,0) / nullif(`o`.`order_count`,0)),2) AS `avg_order_amount` from (((`crest_demo_retail`.`dim_region` `r` join `crest_demo_retail`.`dim_store` `s` on((`s`.`region_id` = `r`.`region_id`))) left join (select `s`.`region_id` AS `region_id`,count(distinct `o`.`order_id`) AS `order_count`,count(distinct `o`.`member_id`) AS `buyer_count`,sum(`o`.`net_amount`) AS `revenue` from (`crest_demo_retail`.`dim_store` `s` join `crest_demo_retail`.`fact_orders` `o` on(((`o`.`store_id` = `s`.`store_id`) and (`o`.`order_status` = '已完成')))) group by `s`.`region_id`) `o` on((`o`.`region_id` = `r`.`region_id`))) left join (select `s`.`region_id` AS `region_id`,sum(`oi`.`item_amount`) AS `item_sales`,sum((`oi`.`item_amount` - (`oi`.`quantity` * `p`.`cost_price`))) AS `gross_profit` from (((`crest_demo_retail`.`dim_store` `s` join `crest_demo_retail`.`fact_orders` `fo` on(((`fo`.`store_id` = `s`.`store_id`) and (`fo`.`order_status` = '已完成')))) join `crest_demo_retail`.`fact_order_items` `oi` on((`oi`.`order_id` = `fo`.`order_id`))) join `crest_demo_retail`.`dim_product` `p` on((`p`.`product_id` = `oi`.`product_id`))) group by `s`.`region_id`) `p` on((`p`.`region_id` = `r`.`region_id`))) group by `r`.`region_id`,`r`.`region_name`,`r`.`city`,`o`.`order_count`,`o`.`buyer_count`,`o`.`revenue`,`p`.`item_sales`,`p`.`gross_profit` order by `revenue` desc;

CREATE OR REPLACE SQL SECURITY INVOKER VIEW `crest_demo_retail`.`v_store_health` AS select `h`.`store_name` AS `store_name`,`h`.`region_name` AS `region_name`,`h`.`revenue` AS `revenue`,`h`.`gross_margin_pct` AS `gross_margin_pct`,`h`.`service_score` AS `service_score`,`h`.`stockout_days` AS `stockout_days`,`h`.`health_score` AS `health_score` from (select `sp`.`store_name` AS `store_name`,`sp`.`region_name` AS `region_name`,`sp`.`revenue` AS `revenue`,round((`sp`.`gross_margin` * 100),2) AS `gross_margin_pct`,round(greatest(0,((100 - (least(((`sp`.`timeout_orders` / nullif(`sp`.`order_count`,0)) * 100),30) * 1.8)) - (least(`sp`.`avg_delivery_minutes`,60) * 0.25))),2) AS `service_score`,coalesce(`ir`.`stockout_days`,0) AS `stockout_days`,round(least(100,greatest(0,((((`sp`.`gross_margin` * 100) * 0.38) + (greatest(0,((100 - (least(((`sp`.`timeout_orders` / nullif(`sp`.`order_count`,0)) * 100),30) * 1.8)) - (least(`sp`.`avg_delivery_minutes`,60) * 0.25))) * 0.34)) + ((100 - least(coalesce(`ir`.`stockout_days`,0),80)) * 0.28)))),2) AS `health_score` from (`crest_demo_retail`.`v_store_performance` `sp` left join (select `crest_demo_retail`.`v_inventory_risk`.`store_name` AS `store_name`,sum(`crest_demo_retail`.`v_inventory_risk`.`stockout_days`) AS `stockout_days` from `crest_demo_retail`.`v_inventory_risk` group by `crest_demo_retail`.`v_inventory_risk`.`store_name`) `ir` on((`ir`.`store_name` = `sp`.`store_name`)))) `h` order by `h`.`health_score` limit 16;

